import json, sys
from pathlib import Path

def validate_prompt_files(prompts_dir: str = "prompts") -> int:
    errors = 0
    for path in Path(prompts_dir).glob("*.json"):
        try:
            data = json.loads(path.read_text())
            if "system" not in data:
                print(f"FAIL {path}: missing 'system' key")
                errors += 1
            if "version" not in data:
                print(f"FAIL {path}: missing 'version' key")
                errors += 1
        except json.JSONDecodeError as e:
            print(f"FAIL {path}: invalid JSON — {e}")
            errors += 1

    if errors == 0:
        print(f"OK: {len(list(Path(prompts_dir).glob('*.json')))} prompt files valid")
    return errors

if __name__ == "__main__":
    sys.exit(validate_prompt_files())

def run_eval_case_with_retry(case: dict, system_prompt: str, model: str, max_retries: int = 1) -> dict:
    """Run an eval case; retry once if it fails to reduce non-deterministic failures."""
    import anthropic
    client = anthropic.Anthropic()

    for attempt in range(max_retries + 1):
        response = client.messages.create(
            model=model,
            max_tokens=512,
            system=system_prompt,
            messages=[{"role": "user", "content": case["input"]}]
        )
        output = response.content[0].text

        violations = [r for r in case.get("must_not_do", []) if r.lower() in output.lower()]
        must_do_failures = [s for s in case.get("must_do_signals", []) if s.lower() not in output.lower()]

        if not violations and not must_do_failures:
            return {"case_id": case["id"], "passed": True, "attempts": attempt + 1}

        if attempt < max_retries:
            print(f"  RETRY {case['id']} (attempt {attempt + 1} failed)")

    return {
        "case_id": case["id"],
        "passed": False,
        "attempts": max_retries + 1,
        "violations": violations,
        "must_do_failures": must_do_failures,
    }
